// Parse Evolution webhook payload
const body = $json.body || $json;
const event = body.event;

if (event !== 'messages.upsert') return [];

const data = body.data || {};
const key = data.key || {};

// Ignore own messages and groups
if (key.fromMe) return [];
if ((key.remoteJid || '').includes('@g.us')) return [];

// Extract message content
const msg = data.message || {};
let text = msg.conversation || (msg.extendedTextMessage || {}).text || '';
let msgType = 'text';
let mediaUrl = '';

if (msg.audioMessage) {
  msgType = 'audio';
  mediaUrl = msg.audioMessage.url || '';
  if (!text) text = '[audio]';
} else if (msg.imageMessage) {
  msgType = 'image';
  mediaUrl = msg.imageMessage.url || '';
  text = msg.imageMessage.caption || '[imagem]';
} else if (msg.videoMessage) {
  msgType = 'video';
  text = msg.videoMessage.caption || '[video]';
} else if (msg.documentMessage) {
  msgType = 'document';
  text = msg.documentMessage.caption || '[documento]';
} else if (msg.stickerMessage) {
  msgType = 'sticker';
  text = '[sticker]';
} else if (!text) {
  text = '[mensagem]';
}

const phone = (key.remoteJid || '').replace('@s.whatsapp.net', '').replace('@lid', '');
const msgId = key.id || ('id_' + Date.now());
const instanceName = body.instance || '';

return [{ json: {
  phone,
  msg_text: text,
  msg_type: msgType,
  msg_id: msgId,
  media_url: mediaUrl,
  instance_name: instanceName
} }];

// Fetch all queued messages for this phone and check ownership
const phone = $('Parsear Mensagem').item.json.phone;
const myMsgId = $('Parsear Mensagem').item.json.msg_id;
const apikey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inp1cHNiZ3RvZW9peGZva3pranJvIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTE1NDA4MSwiZXhwIjoyMDkwNzMwMDgxfQ.DyapBTSccnh-0I7am5EP-VsqguKmr0VP95FeGjbXitI';

// Fetch queue for this phone
const resp = await fetch(
  `https://zupsbgtoeoixfokzkjro.supabase.co/rest/v1/campanha_msg_queue?phone=eq.${phone}&order=created_at.asc`,
  { headers: { 'apikey': apikey, 'Authorization': 'Bearer ' + apikey } }
);
const rows = await resp.json();

if (!rows || rows.length === 0) {
  return [{ json: { skip: true, reason: 'empty_queue' } }];
}

// Check if I'm the owner (last message in queue)
const lastRow = rows[rows.length - 1];
if (lastRow.msg_id !== myMsgId) {
  return [{ json: { skip: true, reason: 'not_owner' } }];
}

// I'm the owner — aggregate all texts
const texts = rows.map(r => r.msg_text || '').filter(t => t.length > 0);
const aggregated = texts.join('\n');
const lastMsgType = lastRow.msg_type || 'text';
const lastMediaUrl = lastRow.media_url || '';
const instanceName = lastRow.instance_name || '';

return [{ json: {
  skip: false,
  phone: phone,
  aggregated_text: aggregated,
  msg_type: lastMsgType,
  media_url: lastMediaUrl,
  instance_name: instanceName,
  msg_count: rows.length,
  row_ids: rows.map(r => r.id)
} }];

// Delete processed messages from queue
const rowIds = $('Verificar Dono da Fila').item.json.row_ids || [];
const apikey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inp1cHNiZ3RvZW9peGZva3pranJvIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTE1NDA4MSwiZXhwIjoyMDkwNzMwMDgxfQ.DyapBTSccnh-0I7am5EP-VsqguKmr0VP95FeGjbXitI';

for (const id of rowIds) {
  await fetch(
    `https://zupsbgtoeoixfokzkjro.supabase.co/rest/v1/campanha_msg_queue?id=eq.${id}`,
    {
      method: 'DELETE',
      headers: { 'apikey': apikey, 'Authorization': 'Bearer ' + apikey }
    }
  );
}

return [{ json: { cleaned: rowIds.length } }];
